// Returns the "winner" element according to the same logic
// implemented in the provided Java method.
int winner(const std::vector<int>& a, int n, int k)
{
    if (k >= n - 1)
        return *std::max_element(a.begin(), a.end());  // equivalent to returning the max element (a[n-1] in Java)
    int best  = 0;
    int times = 0;
    for (int i = 0; i < n; ++i)
    {
        if (a[i] > best)
        {
            best = a[i];
            if (i >= 1)
                times = 1;
        }
        else
        {
            ++times;
        }
        if (times >= k)
            return best;
    }
    return best;
}

