int solveQuery(int start, int end, const vector<int>& arr) {
    unordered_map<int, int> mp;
    // Count frequency of each element in the interval [start, end]
    for (int i = start; i <= end; ++i) {
        ++mp[arr[i]];
    }
    // Count how many elements have frequency equal to their value
    int count = 0;
    for (const auto& entry : mp) {
        if (entry.first == entry.second) {
            ++count;
        }
    }
    return count;
}

