bool isDivisible999(const std::string &input) {
    std::string num = input;        // Work on a mutable copy
    int n = static_cast<int>(num.length());
    // Base-case check
    if (n == 0 && num[0] == '0') return true;
    // Pad with leading zeroes so the length becomes a multiple of 3
    if (n % 3 == 1) num = "00" + num;
    if (n % 3 == 2) num =  "0" + num;
    int gSum = 0;
    // Form groups of 3 digits and accumulate their numeric value
    for (int i = 0; i < n; ++i) {
        int group = 0;
        group += (num[i++] - '0') * 100;   // hundreds place
        group += (num[i++] - '0') * 10;    // tens place
        group +=  num[i]   - '0';          // ones place
        gSum += group;
    }
    // Reduce repeatedly if the intermediary sum exceeds 1000
    if (gSum > 1000) {
        num = std::to_string(gSum);
        n   = static_cast<int>(num.length());
        gSum = isDivisible999(num) ? 1 : 0;
    }
    return (gSum == 999);
}

