// Returns true if given preorder traversal array `pre` (of length `n`) 
// can represent a Binary Search Tree.
bool canRepresentBST(const int pre[], int n) {
    std::stack<int> s;
    int root = INT_MIN;          // Smallest possible value
    for (int i = 0; i < n; ++i) {
        // If we find a node who is on the left side but smaller than current root,
        // then it's not a valid preorder for a BST
        if (pre[i] < root)
            return false;
        // Nodes popped here form the path to the parent of pre[i]
        while (!s.empty() && s.top() < pre[i]) {
            root = s.top();
            s.pop();
        }
        // Push the current key to stack
        s.push(pre[i]);
    }
    return true;
}

