// Function to determine whether the seller can give change
// notes : array/vector of customer notes
// n     : total number of customers
int isChangeable(const std::vector<int>& notes, int n)
{
    int fiveCount = 0;   // Number of available 5-rupee notes
    int tenCount  = 0;   // Number of available 10-rupee notes
    for (int i = 0; i < n; ++i)
    {
        if (notes[i] == 5)
        {
            ++fiveCount;
        }
        else if (notes[i] == 10)
        {
            if (fiveCount > 0)
            {
                --fiveCount;
                ++tenCount;
            }
            else
            {
                return 0;
            }
        }
        else  // notes[i] == 15 (or any value that needs 15-rupee change)
        {
            if (fiveCount > 0 && tenCount > 0)
            {
                --fiveCount;
                --tenCount;
            }
            else if (fiveCount >= 3)
            {
                fiveCount -= 3;
            }
            else
            {
                return 0;
            }
        }
    }
    return 1;
}

