static bool isOverflow(long long a, long long b) {
    // If either operand is zero, multiplication cannot overflow
    if (a == 0 || b == 0) return false;
    // Promote to a wider type to safely perform the multiplication
    __int128 result = static_cast<__int128>(a) * static_cast<__int128>(b);
    // Check whether the result fits in a 64-bit signed integer
    return result > std::numeric_limits<long long>::max() ||
           result < std::numeric_limits<long long>::min();
}

