// Equivalent of the Java `check` method
bool check(const string& s1, const string& s2) {
    int n = static_cast<int>(s1.size());
    int m = static_cast<int>(s2.size());
    // dp[i][j] == true  ->  first i chars of s1 can be transformed to first j chars of s2
    vector<vector<bool>> dp(n + 1, vector<bool>(m + 1, false));
    dp[0][0] = true;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j <= m; ++j) {
            if (!dp[i][j]) continue;
            // 1. Try to match s1[i] (upper-cased) with s2[j]
            if (j < m && std::toupper(static_cast<unsigned char>(s1[i])) == s2[j]) {
                dp[i + 1][j + 1] = true;
            }
            // 2. Optionally delete s1[i] if it is lowercase
            if (!std::isupper(static_cast<unsigned char>(s1[i]))) {
                dp[i + 1][j] = true;
            }
        }
    }
    return dp[n][m];
}

