bool checkReverse(int arr[], int n) {
    if (n == 1) {
        return true;
    }
    int i;
    // Find the first position where the ascending order breaks
    for (i = 1; i < n && arr[i - 1] < arr[i]; ++i)
        ;
    if (i == n) {                      // Entire array is already sorted
        return true;
    }
    int j = i++;                       // Start of the potential reversed segment
    // Traverse the decreasing segment
    while (j < n && arr[j] < arr[j - 1]) {
        if (i > 1 && arr[j] < arr[i - 2]) {
            return false;
        }
        ++j;
    }
    if (j == n) {                      // Reached end, segment reversal sorts the array
        return true;
    }
    int k = j;                         // Start of the remaining part
    if (arr[k] < arr[i - 1]) {         // Element after reversed segment must be ≥ first part’s last element
        return false;
    }
    // Ensure the remaining part is non-decreasing
    while (k > 1 && k < n) {
        if (arr[k] < arr[k - 1]) {
            return false;
        }
        ++k;
    }
    return true;
}

