bool isDivisible7(std::string num)
{
    int n = static_cast<int>(num.length());
    // Special-case : “0”
    if (n == 0 && num[0] == '0')
        return true;
    // Pad on the left so that the length becomes a multiple of 3
    if (n % 3 == 1)
        num = "00" + num;
    else if (n % 3 == 2)
        num = "0" + num;
    n = static_cast<int>(num.length());
    int gSum = 0;   // alternating sum of 3-digit groups
    int p    = 1;   // +1, -1, +1, ...
    for (int i = n - 1; i >= 0; i--)
    {
        int group = 0;
        group +=  (num[i--] - '0');          // units
        group += ((num[i--] - '0') * 10);    // tens
        group += ((num[i]   - '0') * 100);   // hundreds
        gSum += group * p;
        p *= -1;                             // flip sign for next group
    }
    return (gSum % 7 == 0);
}

