void spiralFill(int m, int n, std::vector<std::vector<int>>& a) {
    int val = 1;
    int k = 0, l = 0;          // k -> starting row index, l -> starting column index
    // Continue while there are rows and columns left to fill
    while (k < m && l < n) {
        // 1. Fill the top row (left to right)
        for (int i = l; i < n; ++i) {
            a[k][i] = val++;
        }
        ++k;                   // Move to next row
        // 2. Fill the right-most column (top to bottom)
        for (int i = k; i < m; ++i) {
            a[i][n - 1] = val++;
        }
        --n;                   // Reduce right boundary
        // 3. Fill the bottom row (right to left), if any row remains
        if (k < m) {
            for (int i = n - 1; i >= l; --i) {
                a[m - 1][i] = val++;
            }
            --m;               // Reduce bottom boundary
        }
        // 4. Fill the left-most column (bottom to top), if any column remains
        if (l < n) {
            for (int i = m - 1; i >= k; --i) {
                a[i][l] = val++;
            }
            ++l;               // Move to next column
        }
    }
}

