int countPS(const string& str) {
    int N = static_cast<int>(str.length());
    vector<vector<int>> cps(N + 1, vector<int>(N + 1, 0));
    // Subsequences of length 1 are palindromes by definition.
    for (int i = 0; i < N; ++i)
        cps[i][i] = 1;
    // Build the table for substrings of length L (from 2 to N).
    for (int L = 2; L <= N; ++L) {
        for (int i = 0; i < N; ++i) {
            int k = i + L - 1; // Ending index of current substring
