// Finds the number of groups in 'arr' that satisfy the same criteria as in the Java version.
// Uses 64-bit arithmetic (long long) to avoid intermediate overflow.
long long findgroups(const std::vector<int>& arr)
{
    long long c[3] = {0, 0, 0};          // Counters for values % 3 == 0, 1, 2
    const std::size_t n = arr.size();
    // Count elements according to their remainder when divided by 3
    for (std::size_t i = 0; i < n; ++i)
        ++c[arr[i] % 3];
    long long res = 0;
    // Pairs whose sum is divisible by 3
    res += (c[0] * (c[0] - 1)) >> 1;     // both elements % 3 == 0
    res += c[1] * c[2];                  // one element % 3 == 1, the other % 3 == 2
    // Triplets whose sum is divisible by 3
    res += (c[0] * (c[0] - 1) * (c[0] - 2)) / 6; // all % 3 == 0
    res += (c[1] * (c[1] - 1) * (c[1] - 2)) / 6; // all % 3 == 1
    res += (c[2] * (c[2] - 1) * (c[2] - 2)) / 6; // all % 3 == 2
    res += c[0] * c[1] * c[2];                   // one from each remainder class
    return res;
}

