int sortedCount(const std::vector<std::vector<int>>& mat, int r, int c) {
    int result = 0;
    /* Count strictly increasing rows */
    for (int i = 0; i < r; ++i) {
        int j;
        for (j = 0; j < c - 1; ++j) {
            if (mat[i][j + 1] <= mat[i][j])        // break if not strictly increasing
                break;
        }
        if (j == c - 1)                           // reached the end ⇒ strictly increasing
            ++result;
    }
    /* Count strictly decreasing rows */
    for (int i = 0; i < r; ++i) {
        int j;
        for (j = c - 1; j > 0; --j) {
            if (mat[i][j - 1] <= mat[i][j])       // break if not strictly decreasing
                break;
        }
        if (c > 1 && j == 0)                      // strictly decreasing row (length > 1)
            ++result;
    }
    return result;
}

