std::string decode(const std::string& str) {
    std::stack<int>    integerStack;   // Holds repeat counts
    std::stack<char>   stringStack;    // Holds characters and '['
    std::string temp  = "";
    std::string result = "";
    for (std::size_t i = 0; i < str.length(); ++i) {
        int count = 0;
        /* If current character is a digit, build the full number */
        if (std::isdigit(str[i])) {
            while (i < str.length() && std::isdigit(str[i])) {
                count = count * 10 + (str[i] - '0');
                ++i;
            }
            --i;                       // step back so that the for-loop increments correctly
            integerStack.push(count);
        }
        /* Closing bracket: start decoding */
        else if (str[i] == ']') {
            temp  = "";
            count = 0;
            if (!integerStack.empty()) {
                count = integerStack.top();
                integerStack.pop();
            }
            /* Pop characters until matching '[' */
            while (!stringStack.empty() && stringStack.top() != '[') {
                temp = stringStack.top() + temp;
                stringStack.pop();
            }
            /* Pop the '[' */
            if (!stringStack.empty() && stringStack.top() == '[')
                stringStack.pop();
            /* Repeat the decoded substring `count` times */
            for (int j = 0; j < count; ++j)
                result += temp;
            /* Push the expanded result back onto the stack */
            for (char ch : result)
                stringStack.push(ch);
            result.clear();
        }
        /* Opening bracket handling */
        else if (str[i] == '[') {
            if (i > 0 && std::isdigit(str[i - 1]))
                stringStack.push(str[i]);    // part of k[...]
            else {
                stringStack.push(str[i]);
                integerStack.push(1);        // implicit repeat count 1
            }
        }
        /* Regular character */
        else {
            stringStack.push(str[i]);
        }
    }
    /* Assemble final result */
    while (!stringStack.empty()) {
        result = stringStack.top() + result;
        stringStack.pop();
    }
    return result;
}

