// Returns the value of the Dealnnoy number D(m, n)
int dealnnoy(int n, int m) {
    // dp[i][j] will store D(i, j)
    std::vector<std::vector<int>> dp(m + 1, std::vector<int>(n + 1, 0));
    // Base cases: dp[i][0] = 1 and dp[0][j] = 1
    for (int i = 0; i <= m; ++i) dp[i][0] = 1;
    for (int j = 0; j <= n; ++j) dp[0][j] = 1;
    // Fill the table using the recurrence:
    // D(i, j) = D(i-1, j) + D(i-1, j-1) + D(i, j-1)
    for (int i = 1; i <= m; ++i) {
        for (int j = 1; j <= n; ++j) {
            dp[i][j] = dp[i - 1][j] + dp[i - 1][j - 1] + dp[i][j - 1];
        }
    }
    return dp[m][n];
}

