// Returns the smallest x such that a^x ≡ b (mod m), or -1 if no solution exists.
int discreteLogarithm(int a, int b, int m) {
    // Step 1: set n = ⌈√m⌉
    int n = static_cast<int>(std::sqrt(m) + 1);
    // Step 2: pre-compute a^n  (mod m)
    long long an = 1;
    for (int i = 0; i < n; ++i)
        an = (an * a) % m;
    // Step 3: Baby-steps – store (a^n)^i values in a lookup table
    std::vector<int> value(m, 0);       // value[x] = i  ⇒  (a^n)^i ≡ x (mod m)
    long long cur = an;
    for (int i = 1; i <= n; ++i) {
        if (value[cur] == 0)            // store the first occurrence only
            value[cur] = i;
        cur = (cur * an) % m;
    }
    // Step 4: Giant-steps – try to match against the table
    cur = b;
    for (int i = 0; i <= n; ++i) {
        if (value[cur] > 0) {
            int ans = value[cur] * n - i;
            if (ans < m)                // found the discrete logarithm
                return ans;
        }
        cur = (cur * a) % m;
    }
    // No solution exists
    return -1;
}

