{
    std::string ans;              // Stores result (quotient)
    std::size_t idx = 0;          // Index of current digit
    long long temp = number[idx] - '0';
    /*  Find the first prefix of 'number' that is ≥ divisor  */
    while (temp < divisor && idx + 1 < number.size()) {
        ++idx;
        temp = temp * 10 + (number[idx] - '0');
