    /*  Repeatedly divide by bringing down subsequent digits  */
    while (idx < number.size()) {
        ans += char((temp / divisor) + '0');   // Append quotient digit
        ++idx;
        if (idx == number.size())              // No more digits to bring down
            break;
        temp = (temp % divisor) * 10 + (number[idx] - '0');
    }
    if (ans.empty())               // If quotient is 0
        return "0";
    return ans;
}

