int minPalPartion(const std::string& str) {
    int n = static_cast<int>(str.size());
    if (n == 0) return 0;                        // optional safety check
    std::vector<std::vector<int>>  C(n, std::vector<int>(n));
    std::vector<std::vector<bool>> P(n, std::vector<bool>(n, false));
    // Every single character is a palindrome of length 1
    for (int i = 0; i < n; ++i) {
        P[i][i] = true;
        C[i][i] = 0;
    }
    // L is the length of the substring
    for (int L = 2; L <= n; ++L) {
        for (int i = 0; i < n - L + 1; ++i) {
            int j = i + L - 1;                  // Ending index of substring
            if (L == 2)
                P[i][j] = (str[i] == str[j]);
            else
                P[i][j] = (str[i] == str[j]) && P[i + 1][j - 1];
            if (P[i][j]) {
                C[i][j] = 0;                    // No cut needed if substring is palindrome
            } else {
                C[i][j] = INT_MAX;
                for (int k = i; k <= j - 1; ++k) {
