// Counts the number of ways to parenthesize the given boolean expression
// so that it evaluates to TRUE.
//
// symb : vector containing the symbols ('T' or 'F')
// oper : vector containing the operators ('&', '|', '^')
// n    : number of symbols (symb.size() == n, oper.size() == n - 1)
int countParenth(const std::vector<char>& symb,
                 const std::vector<char>& oper,
                 int n)
{
    // T[i][j] ‑ number of ways sub-expression from i to j is TRUE
    // F[i][j] ‑ number of ways sub-expression from i to j is FALSE
    std::vector<std::vector<int>> T(n, std::vector<int>(n, 0));
    std::vector<std::vector<int>> F(n, std::vector<int>(n, 0));
    // Base cases: single symbol
    for (int i = 0; i < n; ++i) {
        F[i][i] = (symb[i] == 'F') ? 1 : 0;
        T[i][i] = (symb[i] == 'T') ? 1 : 0;
    }
    // gap is current length of sub-expression minus 1
    for (int gap = 1; gap < n; ++gap) {
        for (int i = 0, j = gap; j < n; ++i, ++j) {
            T[i][j] = F[i][j] = 0;      // initialize for this sub-expression
            for (int g = 0; g < gap; ++g) {
                int k   = i + g;        // last operator position in left sub-expression
                int tik = T[i][k] + F[i][k];           // total ways left  sub-exp can be either T or F
                int tkj = T[k + 1][j] + F[k + 1][j];   // total ways right sub-exp can be either T or F
                switch (oper[k]) {
                    case '&':
                        T[i][j] += T[i][k] * T[k + 1][j];
                        F[i][j] += (tik * tkj - T[i][k] * T[k + 1][j]);
                        break;
                    case '|':
                        F[i][j] += F[i][k] * F[k + 1][j];
                        T[i][j] += (tik * tkj - F[i][k] * F[k + 1][j]);
                        break;
                    case '^':
                        T[i][j] += T[i][k] * F[k + 1][j] + F[i][k] * T[k + 1][j];
                        F[i][j] += T[i][k] * T[k + 1][j] + F[i][k] * F[k + 1][j];
                        break;
                }
            }
        }
    }
    // Result for the whole expression
    return T[0][n - 1];
}

