/*
 * Recursive function that returns the minimum cost of multiplying
 * a chain of matrices whose dimensions are stored in array `p`.
 *
 * Parameters
 * ----------
 * p : int[]       – array holding the dimensions
 * i : int         – starting index of the chain
 * j : int         – ending index of the chain
 *
 * Returns
 * -------
 * int             – minimum number of scalar multiplications needed
 */
int MatrixChainOrder(const int p[], int i, int j) {
    if (i == j)
        return 0;
    int minVal = INT_MAX;
    for (int k = i; k < j; ++k) {
        int count = MatrixChainOrder(p, i, k) +
                    MatrixChainOrder(p, k + 1, j) +
                    p[i - 1] * p[k] * p[j];
        if (count < minVal)
            minVal = count;
    }
    return minVal;
}

