// Returns the maximum Hamming distance obtainable by rotating the array.
int maxHamming(const std::vector<int>& arr) {
    int n = static_cast<int>(arr.size());
    if (n == 0) return 0;          // Edge-case: empty array
    // Duplicate the array so every rotation appears as a contiguous block.
    std::vector<int> brr(2 * n + 1);
    for (int i = 0; i < n; ++i) {
        brr[i]     = arr[i];
        brr[n + i] = arr[i];
    }
    int maxHam = 0;
    // Try every rotation (except the 0-shift) and measure Hamming distance.
    for (int i = 1; i < n; ++i) {
        int currHam = 0;
        for (int j = i, k = 0; j < i + n; ++j, ++k) {
            if (brr[j] != arr[k])
                ++currHam;
        }
        if (currHam == n)
            return n;                  // Cannot get better than this.
        maxHam = std::max(maxHam, currHam);
    }
    return maxHam;
}

