struct Indexes
{
    int i, j;
    Indexes() = default;
    Indexes(int _i, int _j) : i(_i), j(_j) {}
    int getI() const { return i; }
    int getJ() const { return j; }
};
/*
 *  Same behaviour as the given Java routine.
 *  arr : array of integers
 *  n   : size of the array
 *  returns the maximum element among the qualifying pairs, or INT_MIN if none found.
 */
int findFourElements(const std::vector<int>& arr, int n)
{
    std::unordered_map<int, Indexes> mp;
    /*  Store every possible pair-sum together with the indices that produced it.
        If several pairs yield the same sum, the last one seen will overwrite
        previous ones – exactly what the original Java HashMap does.            */
    for (int i = 0; i < n - 1; ++i)
    {
        for (int j = i + 1; j < n; ++j)
        {
            mp[arr[i] + arr[j]] = Indexes(i, j);
        }
    }
    int d = std::numeric_limits<int>::min();
    /*  Now look for two other indices (i, j) whose absolute difference equals
        a sum we already stored, making sure all four indices are distinct.      */
    for (int i = 0; i < n - 1; ++i)
    {
        for (int j = i + 1; j < n; ++j)
        {
            int abs_diff = std::abs(arr[i] - arr[j]);
            auto it = mp.find(abs_diff);
            if (it != mp.end())
            {
                const Indexes& idx = it->second;
                if (idx.getI() != i && idx.getI() != j &&
                    idx.getJ() != i && idx.getJ() != j)
                {
                    d = std::max(d, std::max(arr[i], arr[j]));
                }
            }
        }
    }
    return d;
}

