// Function to return the maximum possible equal sum of three stacks.
int maxSum(int stack1[], int stack2[], int stack3[],
           int n1, int n2, int n3) {
    long long sum1 = 0, sum2 = 0, sum3 = 0;   // running sums
    // Compute initial sums of the three stacks
    for (int i = 0; i < n1; ++i) sum1 += stack1[i];
    for (int i = 0; i < n2; ++i) sum2 += stack2[i];
    for (int i = 0; i < n3; ++i) sum3 += stack3[i];
    int top1 = 0, top2 = 0, top3 = 0;          // indices acting as “top” of each stack
    // Iterate until we either find an equal sum or exhaust one stack
    while (true) {
        // If any stack gets empty, equal sum is not possible
        if (top1 == n1 || top2 == n2 || top3 == n3) 
            return 0;
        // If sums are equal, we found the answer
        if (sum1 == sum2 && sum2 == sum3) 
            return static_cast<int>(sum1);
        // Remove element from the stack with the highest current sum
        if (sum1 >= sum2 && sum1 >= sum3) {
            sum1 -= stack1[top1++];
        } else if (sum2 >= sum1 && sum2 >= sum3) {
            sum2 -= stack2[top2++];
        } else { // sum3 is the largest
            sum3 -= stack3[top3++];
        }
    }
}

