// Returns median of a row-wise sorted matrix `m` with `r` rows and `c` columns
int binaryMedian(const vector<vector<int>>& m, int r, int c) {
    int mn = INT_MAX;
    int mx = INT_MIN;
    // Find global minimum (first elements) and maximum (last elements)
    for (int i = 0; i < r; ++i) {
        mn = min(mn, m[i][0]);
        mx = max(mx, m[i][c - 1]);
    }
    int desired = (r * c + 1) / 2;          // position of median in sorted order
    while (mn < mx) {
        int mid   = mn + (mx - mn) / 2;
        int place = 0;
        // Count elements ≤ mid using upper_bound (same as Java logic shown)
        for (int i = 0; i < r; ++i) {
            place += upper_bound(m[i].begin(), m[i].end(), mid) - m[i].begin();
        }
        if (place < desired)
            mn = mid + 1;
        else
            mx = mid;
    }
    return mn;
}

