int sumofFactors(int n)
{
    if (n % 2 != 0) return 0;        // If n is odd, no solution by definition
    int res = 1;
    for (int i = 2; i <= std::sqrt(n); ++i)
    {
        int count     = 0;
        int curr_sum  = 1;
        int curr_term = 1;
        while (n % i == 0)           // Factor out all occurrences of i
        {
            ++count;
            n /= i;
            if (i == 2 && count == 1)  // Special-case for the first factor 2
                curr_sum = 0;
            curr_term *= i;            // i^count
            curr_sum  += curr_term;    // 1 + i + i^2 + … up to current count
        }
        res *= curr_sum;               // Multiply running result by the sum for this prime
    }
    if (n >= 2)                        // Whatever is left is a prime > sqrt(original n)
        res *= (1 + n);
    return res;
}

