// Function to return the sum of all odd factors of n
int sumOfOddFactors(int n) {
    int res = 1;
    // Remove all factors of 2
    while (n % 2 == 0) {
        n /= 2;
    }
    // Iterate over odd potential factors
    for (int i = 3; i <= std::sqrt(n); ++i) {
        int curr_sum  = 1;
        int curr_term = 1;
        // While i divides n, keep reducing n and update sums
        while (n % i == 0) {
            n /= i;
            curr_term *= i;
            curr_sum  += curr_term;
        }
        res *= curr_sum;
    }
    // If n is a prime number greater than 2
    if (n >= 2) {
        res *= (1 + n);
    }
    return res;
}

