// Returns the number of ways to pair up (or leave single) `n` friends.
int countFriendsPairings(int n) {
    std::vector<int> dp(n + 1);
    for (int i = 0; i <= n; ++i) {
        if (i <= 2) {
            dp[i] = i;                                // Base cases: 0->0, 1->1, 2->2
        } else {
            dp[i] = dp[i - 1] + (i - 1) * dp[i - 2];  // Recurrence relation
        }
    }
    return dp[n];
}

