// Returns count of pairs with sum equal to x in a sorted and rotated array.
int pairsInSortedRotated(const std::vector<int>& arr, int x) {
    int n = static_cast<int>(arr.size());
    // Find the index of the largest element (pivot).
    int i;
    for (i = 0; i < n - 1; ++i)
        if (arr[i] > arr[i + 1])
            break;
    int l = (i + 1) % n;       // Index of the smallest element.
    int r = i;                 // Index of the largest element.
    int cnt = 0;
    while (l != r) {
        int currentSum = arr[l] + arr[r];
        if (currentSum == x) {
            ++cnt;
            // If l and r are adjacent, no more pairs are possible.
            if (l == (r + n - 1) % n)
                return cnt;
            l = (l + 1) % n;
            r = (r + n - 1) % n;
        } else if (currentSum < x) {
            l = (l + 1) % n;           // Move left pointer forward.
        } else {
            r = (r + n - 1) % n;       // Move right pointer backward.
        }
    }
    return cnt;
}

