// t        : minimum distance between any two billboards
int maxRevenue(int m,
               const std::vector<int>& x,
               const std::vector<int>& revenue,
               int n,
               int t)
{
    std::vector<int> maxRev(m + 1, 0);   // max revenue up to position i
    int nxtbb = 0;                       // index of next billboard to consider
    for (int i = 1; i <= m; ++i) {
        if (nxtbb < n) {
            if (x[nxtbb] != i) {
                // No billboard at position i
                maxRev[i] = maxRev[i - 1];
