int findInteger(int arr[], int n) {
    std::unordered_map<int, int> hash;
    // Build the frequency difference map
    for (int i = 0; i < n; ++i) {
        int key = std::abs(arr[i]);          // store by absolute value
        int val = hash.count(key) ? hash[key] : 0;
        if (arr[i] < 0)
            hash[key] = val - 1;             // decrement for a negative number
        else
            hash[key] = val + 1;             // increment for a positive number
    }
    // Find the first element whose count is positive
    for (int i = 0; i < n; ++i) {
        if (hash[arr[i]] > 0)                // note: uses the raw value as key (same as Java)
