// Returns the k-th largest sub-array sum
int kthLargestSum(const vector<int>& arr, int n, int k) {
    // Prefix-sum array
    vector<int> sum(n + 1, 0);
    sum[1] = arr[0];
    for (int i = 2; i <= n; ++i)
        sum[i] = sum[i - 1] + arr[i - 1];
    // Min-heap that keeps the k largest sums seen so far
    priority_queue<int, vector<int>, greater<int>> Q;
    for (int i = 1; i <= n; ++i) {
        for (int j = i; j <= n; ++j) {
            int x = sum[j] - sum[i - 1];
            if (static_cast<int>(Q.size()) < k) {
                Q.push(x);
            } else if (Q.top() < x) {
                Q.pop();
                Q.push(x);
            }
        }
    }
    return Q.top();   // k-th largest sum
}

