            else if (set[i] + set[k] > 2 * set[j])
            {
                L[i][j] = 2;
                --i;
            }
            else
            {
                // Found i and k for j, LLAP with i and j as first two elements
                L[i][j] = L[j][k] + 1;
                llap = std::max(llap, L[i][j]);
                --i;
                ++k;
            }
        }
        // If the loop was stopped due to k becoming more than n-1,
        // set the remaining L[i][j] values to 2
        while (i >= 0)
        {
            L[i][j] = 2;
            --i;
        }
    }
    return llap;
}

