// Builds a subsequence `t` from the input array `s`.
//  - `s` : input character array (size >= n)
//  - `t` : output character array (must be large enough)
//  - `n` : length of `s` to consider
//  - `k` : threshold used in the algorithm
void subsequence(const char s[], char t[], int n, int k)
{
    int last = 0, cnt = 0, new_last = 0, size = 0;
    // iterate from 'z' down to 'a'
    for (int ch = 'z'; ch >= 'a'; --ch)
    {
        cnt = 0;
        // count occurrences of the current character in the suffix starting at `last`
        for (int i = last; i < n; ++i)
        {
            if (s[i] == ch)
                ++cnt;
        }
        if (cnt >= k)
        {
            // copy all occurrences of the current character to `t`
            for (int i = last; i < n; ++i)
            {
                if (s[i] == ch)
                {
                    t[size++] = static_cast<char>(ch);
                    new_last = i;
                }
            }
            last = new_last; // move `last` past the last copied character
        }
    }
    t[size] = '\0'; // null-terminate the result
}

