// Returns `true` if the previous (lexicographically smaller) permutation
// exists and modifies `str` in-place to that permutation.
// Returns `false` if `str` is already the smallest permutation.
bool prevPermutation(std::string& str)
{
    int n = static_cast<int>(str.size()) - 1;
    // Step 1: find the longest non-increasing suffix
    int i = n;
    while (i > 0 && str[i - 1] <= str[i]) {
        --i;
    }
    // Entire string is non-decreasing ⇒ already the smallest permutation
    if (i <= 0) {
        return false;
    }
    // Step 2: find rightmost element in the suffix smaller than str[i-1]
    int j = i - 1;
    while (j + 1 <= n && str[j + 1] <= str[i - 1]) {
        ++j;
    }
    // Step 3: make the swap
    std::swap(str[i - 1], str[j]);
    // Step 4: reverse the suffix to get the largest permutation of it
    std::reverse(str.begin() + i, str.end());
    return true;
}

