// Reorders the array `arr` so that it's lexicographically minimal
// using at most `k` adjacent swaps (same logic as the Java version).
void minimizeWithKSwaps(std::vector<int>& arr, int k)
{
    int n = static_cast<int>(arr.size());
    for (int i = 0; i < n - 1 && k > 0; ++i) {
        int pos = i;
        // Find the smallest element within the next `k` positions.
        for (int j = i + 1; j < n; ++j) {
            if (j - i > k) break;
            if (arr[j] < arr[pos]) pos = j;
        }
        // Bring that element to position `i` using adjacent swaps.
        for (int j = pos; j > i; --j) {
            std::swap(arr[j], arr[j - 1]);
        }
        k -= (pos - i);  // Update the remaining swap budget.
    }
}

