// Returns the concatenation of all substrings of `s` after they have been
// sorted in lexicographic (dictionary) order.
std::string lexicographicSubConcat(const std::string& s)
{
    int n = static_cast<int>(s.length());
    long long sub_count = 1LL * n * (n + 1) / 2;          // total #substrings
    std::vector<std::string> arr;
    arr.reserve(static_cast<size_t>(sub_count));
    // Generate all substrings
    for (int i = 0; i < n; ++i)
        for (int len = 1; len <= n - i; ++len)
            arr.emplace_back(s.substr(i, len));
    // Sort them lexicographically
    std::sort(arr.begin(), arr.end());
    // Concatenate the sorted substrings
    std::string res;
    for (const auto& str : arr)
        res += str;
    return res;
}
