int lcs(std::vector<std::vector<std::vector<int>>> &dp,
        const std::vector<int> &arr1, int n,
        const std::vector<int> &arr2, int m,
        int k) 
{
    if (k < 0) return -10000000;
    if (n < 0 || m < 0) return 0;
    int ans = dp[n][m][k];          // fetch memoized value (-1 if not computed)
    if (ans != -1) return ans;      // already computed
    // compute recursively
    ans = std::max(lcs(dp, arr1, n - 1, arr2, m,     k),
                   lcs(dp, arr1, n,     arr2, m - 1, k));
    if (arr1[n - 1] == arr2[m - 1])
        ans = std::max(ans, 1 + lcs(dp, arr1, n - 1, arr2, m - 1, k));
    ans = std::max(ans, 1 + lcs(dp, arr1, n - 1, arr2, m - 1, k - 1));
    return ans;
}

