// Returns length of the longest proper prefix of `s` which is also its suffix
int longestPrefixSuffix(const string& s) {
    int n = static_cast<int>(s.size());
    if (n == 0) return 0;
    vector<int> lps(n, 0);   // LPS array
    int len = 0;             // length of the previous longest prefix suffix
    int i = 1;
    while (i < n) {
        if (s[i] == s[len]) {
            ++len;
            lps[i] = len;
            ++i;
        } else {
            if (len != 0) {
                len = lps[len - 1];  // fall back in the pattern
            } else {
                lps[i] = 0;
                ++i;
            }
        }
    }
    int res = lps[n - 1];
    return (res > n / 2) ? n / 2 : res;
}

