std::string longestRepeatedSubSeq(const std::string& str)
{
    int n = static_cast<int>(str.length());
    /* dp[i][j] stores length of the longest repeated subsequence
       in str[0..i-1] and str[0..j-1] with the additional constraint
       that the two subsequences do not use the same character index
       (i.e., i != j when characters match). */
    std::vector<std::vector<int>> dp(n + 1, std::vector<int>(n + 1, 0));
    // Build the DP table
    for (int i = 1; i <= n; ++i)
    {
        for (int j = 1; j <= n; ++j)
        {
            if (str[i - 1] == str[j - 1] && i != j)
                dp[i][j] = 1 + dp[i - 1][j - 1];
            else
                dp[i][j] = std::max(dp[i][j - 1], dp[i - 1][j]);
        }
    }
    // Reconstruct the string from the DP table
    std::string res;
    int i = n, j = n;
    while (i > 0 && j > 0)
    {
        if (dp[i][j] == dp[i - 1][j - 1] + 1 &&
            str[i - 1] == str[j - 1] && i != j)
        {
            // Character is part of the answer
            res += str[i - 1];
            --i;
            --j;
        }
        else if (dp[i][j] == dp[i - 1][j])
            --i;
        else
            --j;
    }
    // We collected the characters in reverse order
    std::string reverse;
    for (int k = static_cast<int>(res.length()) - 1; k >= 0; --k)
        reverse += res[k];
    return reverse;
}

