/*
 * Returns the lexicographically maximum palindrome that can be obtained
 * from `str` using at most `k` single–character modifications.
 * If it is impossible to make `str` a palindrome with the given budget,
 * the function returns the string "Not possible".
 */
string maximumPalinUsingKChanges(string str, int k)
{
    string palin = str;                 // mutable copy we will modify
    int l = 0, r = static_cast<int>(str.size()) - 1;
    /*-----------------------------------------------------------
      Phase-1:  Make the string a palindrome using minimum edits.
    -----------------------------------------------------------*/
    while (l < r) {
        if (str[l] != str[r]) {
            palin[l] = palin[r] = max(str[l], str[r]);
            --k;                        // one change spent
        }
        ++l; --r;
    }
    if (k < 0)                         // not enough changes
        return "Not possible";
    /*-----------------------------------------------------------
      Phase-2:  Try to upgrade the palindrome to the highest value
               (i.e. fill as many '9's as possible) while staying
               within the remaining change budget.
    -----------------------------------------------------------*/
    l = 0; r = static_cast<int>(str.size()) - 1;
    while (l <= r) {
        if (l == r) {                  // middle character in odd length
            if (k > 0)
                palin[l] = '9';
        }
        if (palin[l] < '9') {          // can still be improved
            /* Case-1: both sides were untouched in phase-1 */
            if (k >= 2 && palin[l] == str[l] && palin[r] == str[r]) {
                k -= 2;
                palin[l] = palin[r] = '9';
            }
            /* Case-2: at least one side was changed in phase-1 */
            else if (k >= 1 && (palin[l] != str[l] || palin[r] != str[r])) {
                --k;
                palin[l] = palin[r] = '9';
            }
        }
        ++l; --r;
    }
    return palin;
}

