// Translated from the given Java implementation.
int findMaxVal(const std::vector<int>& arr, int n, int num, int maxLimit) {
    // dp[ind][val] == 1 means it is possible to obtain `val`
    // after processing elements 0..ind (inclusive).
    std::vector<std::vector<int>> dp(n, std::vector<int>(maxLimit + 1, 0));
    for (int ind = 0; ind < n; ++ind) {
        for (int val = 0; val <= maxLimit; ++val) {
            if (ind == 0) {
                // Base case: only the first element is considered.
                if (num - arr[ind] == val || num + arr[ind] == val) {
                    dp[ind][val] = 1;
                } else {
                    dp[ind][val] = 0;
                }
            } else {
                // General case: rely on previously computed row (ind - 1).
                if (val - arr[ind] >= 0 && val + arr[ind] <= maxLimit) {
                    if (dp[ind - 1][val - arr[ind]] == 1 ||
                        dp[ind - 1][val + arr[ind]] == 1) {
                        dp[ind][val] = 1;
                    }
                } else if (val - arr[ind] >= 0) {
                    dp[ind][val] = dp[ind - 1][val - arr[ind]];
                } else if (val + arr[ind] <= maxLimit) {
                    dp[ind][val] = dp[ind - 1][val + arr[ind]];
                } else {
                    dp[ind][val] = 0;
                }
            }
        }
    }
    // Find the maximum value reachable (from maxLimit downwards).
    for (int val = maxLimit; val >= 0; --val) {
        if (dp[n - 1][val] == 1) {
            return val;
        }
    }
    return -1;  // No valid value found.
}

