double largestSumOfAverages(const std::vector<int>& A, int K) {
    int n = static_cast<int>(A.size());
    // Prefix sums
    std::vector<double> pre_sum(n + 1, 0.0);
    for (int i = 0; i < n; ++i) {
        pre_sum[i + 1] = pre_sum[i] + A[i];
    }
    // dp[i] : maximum score starting from index i
    std::vector<double> dp(n, 0.0);
    // Base case: no more cuts, the whole suffix is one part
    for (int i = 0; i < n; ++i) {
        dp[i] = (pre_sum[n] - pre_sum[i]) / (n - i);
    }
    // Add up to K-1 additional cuts
    for (int k = 0; k < K - 1; ++k) {
        for (int i = 0; i < n; ++i) {
            for (int j = i + 1; j < n; ++j) {
                double cur = (pre_sum[j] - pre_sum[i]) / (j - i) + dp[j];
                dp[i] = std::max(dp[i], cur);
            }
        }
    }
    return dp[0];
}

