// such that the row providing the larger sum appears after the other row.
int maxRowDiff(const std::vector<std::vector<int>>& mat, int m, int n) {
    std::vector<int> rowSum(m, 0);
    // Compute sum of every row
    for (int i = 0; i < m; ++i) {
        int sum = 0;
        for (int j = 0; j < n; ++j) {
            sum += mat[i][j];
        }
        rowSum[i] = sum;
    }
    // Initialize max difference and minimum element encountered so far
    int max_diff    = rowSum[1] - rowSum[0];
    int min_element = rowSum[0];
