    for (int i = 1; i < m; ++i) {
        if (rowSum[i] - min_element > max_diff) {
            max_diff = rowSum[i] - min_element;
        }
        if (rowSum[i] < min_element) {
            min_element = rowSum[i];
        }
    }
    return max_diff;
}

