// Returns the maximum number of chocolates that can be distributed
int maxNumOfChocolates(int arr[], int n, int k) {
    unordered_map<int, int> um;         // remainder -> first index
    vector<int> prefixSum(n);
    int curr_rem;
    int maxSum = 0;
    // Build prefix-sum array
    prefixSum[0] = arr[0];
    for (int i = 1; i < n; ++i)
        prefixSum[i] = prefixSum[i - 1] + arr[i];
    // Traverse prefix sums
    for (int i = 0; i < n; ++i) {
        curr_rem = ((prefixSum[i] % k) + k) % k; // ensure non-negative remainder
        if (curr_rem == 0) {
            // Whole segment [0..i] is divisible by k
            maxSum = max(maxSum, prefixSum[i]);
        } else if (um.find(curr_rem) == um.end()) {
            // First time this remainder is seen
            um[curr_rem] = i;
        } else {
            // Found a previous prefix with the same remainder
            int segmentSum = prefixSum[i] - prefixSum[um[curr_rem]];
            maxSum = max(maxSum, segmentSum);
        }
    }
    return maxSum / k;
}

