// Returns the maximum sub-array sum with at most one element removed.
int maxSumSubarrayRemovingOneEle(const std::vector<int>& arr)
{
    int n = static_cast<int>(arr.size());
    if (n == 0)
        return 0;
    if (n == 1)
        return arr[0];
    std::vector<int> fw(n), bw(n);
    // Forward pass: maximum sub-array sum ending at i
    int cur_max = arr[0], max_so_far = arr[0];
    fw[0] = arr[0];
    for (int i = 1; i < n; ++i) {
        cur_max = std::max(arr[i], cur_max + arr[i]);
        max_so_far = std::max(max_so_far, cur_max);
        fw[i] = cur_max;
    }
    // Backward pass: maximum sub-array sum starting at i
    cur_max = max_so_far = bw[n - 1] = arr[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        cur_max = std::max(arr[i], cur_max + arr[i]);
        max_so_far = std::max(max_so_far, cur_max);
        bw[i] = cur_max;
    }
    // Answer considering deletion or no deletion
    int ans = max_so_far;                       // no deletion
    for (int i = 1; i < n - 1; ++i)             // delete element at i
        ans = std::max(ans, fw[i - 1] + bw[i + 1]);
    return ans;
}

