// Function to find the maximum sum under the given constraints
int maxSum(const std::vector<int>& arr, int N, int k) {
    // Auxiliary array to store maximum sums from each index to the end
    std::vector<int> MS(N);
    // Base case: last element
    MS[N - 1] = arr[N - 1];
    // Fill the MS array from right to left
    for (int i = N - 2; i >= 0; --i) {
        // If the next valid (i + k + 1) index is out of bounds
        if (i + k + 1 >= N) {
            MS[i] = std::max(arr[i], MS[i + 1]);
        } else {
            MS[i] = std::max(arr[i] + MS[i + k + 1], MS[i + 1]);
        }
    }
    return MS[0];
}

