int maxCost(const std::vector<std::vector<int>>& mat, int N) {
    // dp[i][j] will store the maximum cost to reach position (i, j)
    std::vector<std::vector<int>> dp(N, std::vector<int>(N, 0));
    dp[0][0] = mat[0][0];
    // First column – can only come from the element directly above
    for (int i = 1; i < N; ++i)
        dp[i][0] = mat[i][0] + dp[i - 1][0];
    // Fill the rest of the dp table
    for (int i = 1; i < N; ++i) {
        for (int j = 1; j < N && j < i + 1; ++j) {
            dp[i][j] = mat[i][j] + std::max(dp[i - 1][j - 1], dp[i - 1][j]);
        }
    }
    // Find the maximum in the last row
    int result = 0;
    for (int i = 0; i < N; ++i)
        result = std::max(result, dp[N - 1][i]);
    return result;
}

