int getMedian(const int ar1[], const int ar2[], int n) {
    int i = 0;          // Current index of ar1
    int j = 0;          // Current index of ar2
    int m1 = -1, m2 = -1;
    // Since total number of elements is 2n, the median will be
    // the average of the n-th and (n+1)-th elements (1-based indexing),
    // i.e. the n-1 and n elements in 0-based indexing.
    for (int count = 0; count <= n; ++count) {
        // If we have exhausted ar1, take element from ar2
        if (i == n) {
            m1 = m2;
            m2 = ar2[0];
            break;
        }
        // If we have exhausted ar2, take element from ar1
        else if (j == n) {
            m1 = m2;
            m2 = ar1[0];
            break;
        }
        if (ar1[i] < ar2[j]) {
            m1 = m2;       // Store previous median
            m2 = ar1[i];
            ++i;
        } else {
            m1 = m2;       // Store previous median
            m2 = ar2[j];
            ++j;
        }
    }
    return (m1 + m2) / 2;
}

