// Helper alias for the 3-D DP table
/*
 * Recursive DP:
 *  X, Y  : input strings (treated like the char[] in the Java version)
 *  l, r  : current indices in X and Y
 *  k     : number of characters we still need to match/pick
 *  dp    : memoization table (-1 means “not computed yet”)
 */
int solve(const string& X, const string& Y,
          int l, int r, int k, DPTable& dp)
{
    if (k == 0)                  return 0;
    if (l < 0 || r < 0)          return static_cast<int>(1e9);
    int& memo = dp[l][r][k];
    if (memo != -1)              return memo;
    int cost = (X[l] - 'a') ^ (Y[r] - 'a');
    // Three choices, exactly like the Java code
    int option1 = cost + solve(X, Y, l - 1, r - 1, k - 1, dp); // take both chars
    int option2 = solve(X, Y, l - 1, r,     k,     dp);        // skip X[l]
    int option3 = solve(X, Y, l,     r - 1, k,     dp);        // skip Y[r]
    return memo = min({option1, option2, option3});
}

