int MinimumCost(const std::vector<int>& cost, int n, int W) {
    std::vector<int> val;     // stores cost of available packets
    std::vector<int> wt;      // stores corresponding weights (1-based index)
    // Filter packets that have valid cost (cost[i] != -1)
    for (int i = 0; i < n; ++i) {
        if (cost[i] != -1) {
            val.push_back(cost[i]);
            wt.push_back(i + 1);  // weight of the i-th packet is (i + 1)
        }
    }
    n = static_cast<int>(val.size());      // new number of available packets
    const int INF = INT_MAX;
    // DP table: min_cost[i][j] -> minimum cost to achieve weight j using
    // first i packet types
    std::vector<std::vector<int>> min_cost(n + 1, std::vector<int>(W + 1, 0));
    // Initialize first row (0 packet types): impossible for j > 0
    for (int j = 0; j <= W; ++j) {
        min_cost[0][j] = (j == 0) ? 0 : INF;
    }
    // Initialize first column (weight 0): cost is 0
    for (int i = 1; i <= n; ++i) {
        min_cost[i][0] = 0;
    }
    // Fill the DP table
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= W; ++j) {
            if (wt[i - 1] > j) {
                // Current packet weight exceeds j -> can't include it
                min_cost[i][j] = min_cost[i - 1][j];
            } else {
                // Option 1: don't take current packet
                int without_curr = min_cost[i - 1][j];
                // Option 2: take current packet (unbounded, so stay at i)
                int with_curr = (min_cost[i][j - wt[i - 1]] == INF)
                                ? INF
                                : min_cost[i][j - wt[i - 1]] + val[i - 1];
                min_cost[i][j] = std::min(without_curr, with_curr);
            }
        }
    }
    return (min_cost[n][W] == INF) ? -1 : min_cost[n][W];
}

