/*
 * Returns length of the smallest sub-array whose sum 
 * is greater than the given value x.
 */
int smallestSubWithSum(int arr[], int n, int x)
{
    int curr_sum = 0, min_len = n + 1;
    int start = 0, end = 0;
    while (end < n)
    {
        // Keep adding array elements while current sum is
        // less than or equal to x and end hasn’t reached the end.
        while (curr_sum <= x && end < n)
        {
            // If current sum becomes non-positive and x is positive,
            // reset the window to start from current end index.
            if (curr_sum <= 0 && x > 0)
            {
                start = end;
                curr_sum = 0;
            }
            curr_sum += arr[end++];
        }
        // If current sum becomes greater than x, try to shrink the window
        // from the left to find the minimum length.
        while (curr_sum > x && start < n)
        {
            if (end - start < min_len)
                min_len = end - start;
            curr_sum -= arr[start++];
        }
    }
    return min_len;
}

