/*
 * Returns the minimum number of jumps to reach the end of `arr`.
 * If it is not possible, the function returns INT_MAX.
 */
int minJumps(const vector<int>& arr) {
    int n = static_cast<int>(arr.size());
    // Base cases
    if (n == 0 || arr[0] == 0) 
        return INT_MAX;
    vector<int> jumps(n, INT_MAX);
    jumps[0] = 0;                       // Start position needs 0 jumps
    // Build the jumps[] array iteratively
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < i; ++j) {
            if (i <= j + arr[j] && jumps[j] != INT_MAX) {
                jumps[i] = min(jumps[i], jumps[j] + 1);
                break;                  // Found the minimum jumps for i
            }
        }
    }
    return jumps[n - 1];
}

