// Returns minimum number of jumps to reach end of array `arr` of size `n`
int minJumps(int arr[], int n) {
    std::vector<int> jumps(n);
    int mn;
    jumps[n - 1] = 0;                       // No jumps needed from the last element
    for (int i = n - 2; i >= 0; --i) {
        if (arr[i] == 0) {                  // Cannot move anywhere from this index
            jumps[i] = INT_MAX;
        } else if (arr[i] >= n - i - 1) {   // Can reach the end directly
            jumps[i] = 1;
        } else {
            mn = INT_MAX;
            // Check all positions reachable from i and choose minimum jumps among them
            for (int j = i + 1; j < n && j <= arr[i] + i; ++j) {
                if (mn > jumps[j])
                    mn = jumps[j];
            }
            jumps[i] = (mn != INT_MAX) ? mn + 1 : mn; // If reachable, add 1 jump
        }
    }
    return jumps[0];                         // Minimum jumps needed from first index
}

