// Returns the minimum number of perfect-square numbers whose sum equals n.
int getMinSquares(int n) {
    if (n <= 3) return n;
    std::vector<int> dp(n + 1);
    dp[0] = 0;
    dp[1] = 1;
    dp[2] = 2;
    dp[3] = 3;
    for (int i = 4; i <= n; ++i) {
        dp[i] = i;                       // Maximum count (1^2 added i times)
        // Try every square number less than or equal to i
        for (int x = 1; x * x <= i; ++x) {
            int square = x * x;
            dp[i] = std::min(dp[i], 1 + dp[i - square]);
        }
    }
    return dp[n];
}

