// Returns the minimum number of operations described in the Java version.
int minOperation(const std::vector<int>& arr, int n) {
    std::unordered_map<int, int> hash;
    // Count frequency of each element
    for (int i = 0; i < n; ++i) {
        ++hash[arr[i]];
    }
    // Find the maximum frequency
    int max_count = 0;
    for (const auto& kv : hash) {
        max_count = std::max(max_count, kv.second);
    }
    // Result is total elements minus the most frequent element count
    return n - max_count;
}

