long long minPerimeter(int n) {
    int l  = static_cast<int>(std::sqrt(n));
    int sq = l * l;
    if (sq == n) {
        return 4LL * l;          // Perfect square: perimeter is 4 * side
    } else {
        long long row      = n / l;                 // Number of columns for full rows
        long long perimeter = 2LL * (l + row);      // Base perimeter with filled grid
        if (n % l != 0) {        // If there is an incomplete row/col, add the extra edges
            perimeter += 2LL;
        }
        return perimeter;
    }
}

