int minProduct(const std::vector<int>& arr, int n, int k) {
    // Min-heap (equivalent to Java's PriorityQueue with natural ordering)
    std::priority_queue<int, std::vector<int>, std::greater<int>> pq;
    // Insert all elements into the heap
    for (int i = 0; i < n; ++i) {
        pq.push(arr[i]);
    }
    int count = 0;
    int ans   = 1;
    // Extract the smallest elements up to k times
    while (!pq.empty() && count < k) {
        ans += pq.top();
        pq.pop();
        ++count;
    }
    return ans;
}

