// Function to compute the minimum product after modifying
// exactly one element of array a by either +2*k or -2*k.
int minProduct(int a[], int b[], int n, int k)
{
    int diff = 0;   // maximum difference achievable
    int res  = 0;   // original sum of products
    for (int i = 0; i < n; ++i)
    {
        int pro  = a[i] * b[i]; // current product
        res += pro;
        int temp = 0;           // product after potential modification
        if (pro < 0 && b[i] < 0)
            temp = (a[i] + 2 * k) * b[i];
        else if (pro < 0 && a[i] < 0)
            temp = (a[i] - 2 * k) * b[i];
        else if (pro > 0 && a[i] < 0)
            temp = (a[i] + 2 * k) * b[i];
        else if (pro > 0 && a[i] > 0)
            temp = (a[i] - 2 * k) * b[i];
        int d = std::abs(pro - temp); // possible reduction in total sum
        if (d > diff)
            diff = d;
    }
    return res - diff;
}

