int minTimeForWritingChars(int N, int insertCost, int removeCost, int copyCost) {
    if (N == 0) return 0;
    if (N == 1) return insertCost;
    std::vector<int> dp(N + 1, 0);   // dp[i] holds the minimum time to get exactly i characters
    for (int i = 1; i <= N; ++i) {
        if (i % 2 == 0) {
            // Option 1: insert one more char after reaching (i-1)
            // Option 2: copy the entire (i/2) substring
            dp[i] = std::min(dp[i - 1] + insertCost,
                             dp[i / 2] + copyCost);
        } else {
            // Option 1: insert one more char after reaching (i-1)
            // Option 2: copy (i+1)/2 chars then remove one extra
            dp[i] = std::min(dp[i - 1] + insertCost,
                             dp[(i + 1) / 2] + copyCost + removeCost);
        }
    }
    return dp[N];
}

