// Computes the N-th root of A using Newton–Raphson iteration
double nthRoot(int A, int N)
{
    // Equivalent to `new Random(1)` and `nextDouble()`
    std::mt19937                      rng(1);                 // deterministic seed
    std::uniform_real_distribution<> dist(0.0, 1.0);
    double xPre = std::fmod(dist(rng), 10.0);                 // initial guess
    const double eps  = 0.001;                                // desired precision
    double       delX = std::numeric_limits<double>::max();   // difference tracker
    double       xK   = 0.0;                                  // current approximation
    while (delX > eps) {
        xK   = ( (N - 1.0) * xPre + static_cast<double>(A) /
                 std::pow(xPre, N - 1) ) / static_cast<double>(N);
        delX = std::fabs(xK - xPre);
        xPre = xK;
    }
    return xK;
}

