int maxDifference(vector<int>& arr, int N, int k) {
    int M, S = 0, S1 = 0, max_difference = 0;
    // Calculate total sum of array elements
    for (int i = 0; i < N; ++i)
        S += arr[i];
    // Sort the array in descending order (simple selection sort as in the Java code)
    for (int i = 0; i < N; ++i) {
        for (int j = i + 1; j < N; ++j) {
            if (arr[i] < arr[j]) {
                int temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
            }
        }
    }
    // Choose the larger partition size between k and N - k
    M = max(k, N - k);
    // Sum the first M elements (largest ones after sorting)
    for (int i = 0; i < M; ++i)
        S1 += arr[i];
    // Calculate maximum difference
    max_difference = S1 - (S - S1);
    return max_difference;
}

