// Calculates the maximum possible average of a path from (0,0) to (N-1,N-1),
// moving only right or down, in an N x N grid.
double maxAverageOfPath(const std::vector<std::vector<int>>& cost, int N) {
    if (N == 0) return 0.0;
    // dp[i][j] holds the maximum sum attainable to cell (i, j)
    std::vector<std::vector<int>> dp(N, std::vector<int>(N, 0));
    dp[0][0] = cost[0][0];
    // First column
    for (int i = 1; i < N; ++i)
        dp[i][0] = dp[i - 1][0] + cost[i][0];
    // First row
    for (int j = 1; j < N; ++j)
        dp[0][j] = dp[0][j - 1] + cost[0][j];
    // Remaining cells
    for (int i = 1; i < N; ++i) {
        for (int j = 1; j < N; ++j) {
            dp[i][j] = std::max(dp[i - 1][j], dp[i][j - 1]) + cost[i][j];
        }
    }
    // Total steps in the path = 2*N - 1 (cells visited, including start)
    return static_cast<double>(dp[N - 1][N - 1]) / (2 * N - 1);
}

