{
    int i, k = 0, l = 0;
    std::stack<int> stk;
    // m and n are assumed to be the last valid indices (rows-1, cols-1)
    while (k <= m && l <= n)
    {
        // Traverse the first row from the remaining rows
        for (i = l; i <= n; ++i)
            stk.push(a[k][i]);
        ++k;
        // Traverse the last column from the remaining columns
        for (i = k; i <= m; ++i)
            stk.push(a[i][n]);
        --n;
