        if (k <= m)
        {
            for (i = n; i >= l; --i)
                stk.push(a[m][i]);
            --m;
        }
        // Traverse the first column from the remaining columns (if any)
        if (l <= n)
        {
            for (i = m; i >= k; --i)
                stk.push(a[i][l]);
            ++l;
        }
    }
    // Print elements in anti-spiral order
    while (!stk.empty())
