int find_maximum(const vector<int>& a, int n, int k) {
    unordered_map<int, int> b;                          // stores the minimum distance for each value
    for (int i = 0; i < n; ++i) {
        int x = a[i];
        int d = min(1 + i, n - i);                     // distance from the closest end (1-indexed)
        auto it = b.find(x);
        if (it == b.end())
            b[x] = d;                                  // first occurrence
        else
            b[x] = min(d, it->second);                 // keep the minimum distance
    }
    int ans = INT_MAX;
    for (int i = 0; i < n; ++i) {
        int x = a[i];
        if (x != k - x && b.count(k - x))              // ensure distinct pair exists
            ans = min(ans, max(b[x], b[k - x]));       // update answer
    }
    return ans;
}

