// Best-Fit memory allocation
void bestFit(std::vector<int>& blockSize, int m,
             std::vector<int>& processSize, int n)
{
    // Stores block index for every process. -1 means not allocated
    std::vector<int> allocation(n, -1);
    // Pick each process one by one
    for (int i = 0; i < n; ++i) {
        int bestIdx = -1;
        // Find the best block for current process
        for (int j = 0; j < m; ++j) {
            if (blockSize[j] >= processSize[i]) {           // block can accommodate process
                if (bestIdx == -1)                          // first suitable block found
                    bestIdx = j;
                else if (blockSize[bestIdx] > blockSize[j]) // choose the tighter fit
                    bestIdx = j;
            }
        }
        // If we found a block for the current process
        if (bestIdx != -1) {
            allocation[i] = bestIdx;              // store block index
            blockSize[bestIdx] -= processSize[i]; // reduce available size
        }
    }
    // Display the allocation result
    std::cout << "\nProcess No.\tProcess Size\tBlock no.\n";
    for (int i = 0; i < n; ++i) {
        std::cout << "   " << (i + 1) << "\t\t"
                  << processSize[i] << "\t\t";
        if (allocation[i] != -1)
            std::cout << allocation[i] + 1; // +1 to match 1-based indexing in output
        else
            std::cout << "Not Allocated";
        std::cout << '\n';
    }
}

