// Haversine formula to compute the great-circle distance between two points
// latitudes/longitudes are expected in **degrees**
double distance(double lat1, double lat2, double lon1, double lon2)
{
    auto toRadians = [](double deg) { return deg * M_PI / 180.0; };
    lon1 = toRadians(lon1);
    lon2 = toRadians(lon2);
    lat1 = toRadians(lat1);
    lat2 = toRadians(lat2);
    double dlon = lon2 - lon1;
    double dlat = lat2 - lat1;
    double a = std::pow(std::sin(dlat / 2.0), 2) +
               std::cos(lat1) * std::cos(lat2) * std::pow(std::sin(dlon / 2.0), 2);
