void worstFit(std::vector<int>& blockSize, int m,
              const std::vector<int>& processSize, int n) {
    // Stores block index for each process (-1 ⇒ not allocated)
    std::vector<int> allocation(n, -1);
    // Pick each process one by one
    for (int i = 0; i < n; ++i) {
        int wstIdx = -1;                       // Index of worst (largest) block
        // Find the largest block that can accommodate process i
        for (int j = 0; j < m; ++j) {
