        if (wstIdx != -1) {
            allocation[i]   = wstIdx;
            blockSize[wstIdx] -= processSize[i];
        }
    }
    // Display allocation table
    std::cout << "\nProcess No.\tProcess Size\tBlock no.\n";
    for (int i = 0; i < n; ++i) {
