 */
void rearrange(std::vector<int>& arr, int n)
{
    int max_idx = n - 1, min_idx = 0;
    int max_elem = arr[n - 1] + 1;          // Element to be used for encoding
    // Store two elements at every index using the encoding technique
    for (int i = 0; i < n; ++i)
    {
        if (i % 2 == 0)                     // Even index : put maximum element
        {
            arr[i] += (arr[max_idx] % max_elem) * max_elem;
