            arr[i] += (arr[min_idx] % max_elem) * max_elem;
            ++min_idx;
        }
    }
    // Decode the elements to get the desired arrangement
    for (int i = 0; i < n; ++i)
        arr[i] = arr[i] / max_elem;
}

