// Returns the minimum number of removals from `arr` (size `n`)
// so that the remaining elements satisfy: 2 * (min element) > (max element).
int minRemovalsDP(int arr[], int n) {
    int longest_start = -1, longest_end = 0;
    for (int start = 0; start < n; ++start) {
        int mn = INT_MAX, mx = INT_MIN;
        for (int end = start; end < n; ++end) {
            int val = arr[end];
            if (val < mn) mn = val;
            if (val > mx) mx = val;
            // If condition is violated, stop extending this sub-array
            if (2 * mn <= mx) break;
            // Track the longest valid sub-array found so far
            if (longest_start == -1 || end - start > longest_end - longest_start) {
                longest_start = start;
                longest_end   = end;
            }
        }
    }
    // No valid sub-array found → need to remove all elements
    if (longest_start == -1) return n;
    // Remove elements outside the longest valid sub-array
    return n - (longest_end - longest_start + 1);
}

