// Translates the provided Java function into C++.
// The function applies a quadratic transformation to each element
// then partially sorts the array as per the original algorithm.
void sortArray(std::vector<int>& arr, int n, int A, int B, int C) {
    // Apply the quadratic transformation: A*x^2 + B*x + C
    for (int i = 0; i < n; ++i) {
        arr[i] = A * arr[i] * arr[i] + B * arr[i] + C;
    }
    // Find the maximum element and its index.
    int index   = -1;
    int maximum = INT_MIN;   // Use a very small sentinel value.
    for (int i = 0; i < n; ++i) {
        if (maximum < arr[i]) {
            index   = i;
            maximum = arr[i];
        }
    }
    // Merge‐like pass from both ends toward the maximum element.
    int i = 0, j = n - 1;
    std::vector<int> new_arr(n);
    int k = 0;
    while (i < index && j > index) {
        if (arr[i] < arr[j])
            new_arr[k++] = arr[i++];
        else
            new_arr[k++] = arr[j--];
    }
    while (i < index)
        new_arr[k++] = arr[i++];
    while (j > index)
        new_arr[k++] = arr[j--];
    // Place the maximum at the end.
    new_arr[n - 1] = maximum;
    // Copy back to the original array.
    for (int p = 0; p < n; ++p)
        arr[p] = new_arr[p];
}

