int KnapSack(const std::vector<int>& val, const std::vector<int>& wt,
             int n, int W)
{
    // Equivalent to: int mat[2][W + 1] in Java (created at run-time)
    std::vector<std::vector<int>> mat(2, std::vector<int>(W + 1, 0));
    for (int i = 0; i < n; ++i) {
        if (i % 2 != 0) {                   // i is odd  ➜  update row 1
            for (int j = 1; j <= W; ++j) {
                if (wt[i] <= j && j - wt[i] < W) {
                    mat[1][j] = std::max(val[i] + mat[0][j - wt[i]], mat[0][j]);
                } else {
                    mat[1][j] = mat[0][j];
                }
            }
        } else {                            // i is even ➜  update row 0
            for (int j = 1; j <= W; ++j) {
                if (wt[i] <= j && j - wt[i] < W) {
                    mat[0][j] = std::max(val[i] + mat[1][j - wt[i]], mat[1][j]);
                } else {
                    mat[0][j] = mat[1][j];
                }
            }
        }
    }
    return (n % 2 != 0) ? mat[0][W] : mat[1][W];
}

