int KnapSack(const std::vector<int>& val, const std::vector<int>& wt, int n, int W) {
    std::vector<int> dp(W + 1, 0);          // dp[j] holds the best value for weight j
    for (int i = 0; i < n; ++i) {
        for (int j = W; j >= 0; --j) {      // iterate backwards to avoid re-using the same item
            int prev = j - wt[i];
            if (prev >= 0)
                dp[j] = std::max(dp[j], val[i] + dp[prev]);
        }
    }
    return dp[W];
}

