static int gcd(int a, int b) {
    if (a == 0) return b;
    if (b == 0) return a;
    int k;
    for (k = 0; ((a | b) & 1) == 0; ++k) {  // both a and b are even
        a >>= 1;
        b >>= 1;
    }
    while ((a & 1) == 0)               // make a odd
        a >>= 1;
    do {
        while ((b & 1) == 0)           // make b odd
            b >>= 1;
        if (a > b) {                   // ensure a <= b
            int temp = a;
            a = b;
            b = temp;
        }
        b = b - a;                     // b now has the difference
    } while (b != 0);
    return a << k;                     // restore common factors of 2
}

