// Binary GCD (Stein’s) algorithm
int gcd(int a, int b)
{
    if (a == b) return a;
    if (a == 0) return b;
    if (b == 0) return a;
    // a is even
    if ((~a & 1) == 1) {
        // b is odd
        if ((b & 1) == 1)
            return gcd(a >> 1, b);
        // both a and b are even
        else
            return gcd(a >> 1, b >> 1) << 1;
    }
    // a is odd, b is even
    if ((~b & 1) == 1)
        return gcd(a, b >> 1);
    // both a and b are odd, a > b
    if (a > b)
        return gcd((a - b) >> 1, b);
    // both a and b are odd, b >= a
    return gcd((b - a) >> 1, a);
}

