int sumoflength(const vector<int>& arr, int n) {
    unordered_set<int> s;       // Stores current window's distinct elements
    int j = 0;                  // Right boundary of the window
    long long ans = 0;          // Use long long to avoid overflow
    for (int i = 0; i < n; ++i) {
        // Expand the window while elements remain distinct
        while (j < n && s.find(arr[j]) == s.end()) {
            s.insert(arr[j]);
            ++j;
