// Computes the sum of squares of the binomial coefficients of (n choose k)
long long sumOfSquare(int n) {
    // Create a (n+1) x (n+1) table initialized with 0
    std::vector<std::vector<long long>> C(n + 1, std::vector<long long>(n + 1, 0));
    // Build Pascal's triangle up to row n
    for (int i = 0; i <= n; ++i) {
        for (int j = 0; j <= std::min(i, n); ++j) {
            if (j == 0 || j == i) {
                C[i][j] = 1;  // edge of the triangle
            } else {
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j];  // Pascal's rule
            }
        }
    }
    // Compute the sum of squares of the nth row
    long long sum = 0;
    for (int i = 0; i <= n; ++i) {
        sum += C[n][i] * C[n][i];
    }
    return sum;
}
