    for (int i = 0; i < n1; ++i) {
        int sum = (str1[i] - '0') + (str2[i] - '0') + carry;
        result.push_back(static_cast<char>(sum % 10 + '0'));
        carry = sum / 10;
    }
    // Add remaining digits of the longer string
    for (int i = n1; i < n2; ++i) {
        int sum = (str2[i] - '0') + carry;
        result.push_back(static_cast<char>(sum % 10 + '0'));
        carry = sum / 10;
    }
    // Append final carry, if any
    if (carry > 0)
        result.push_back(static_cast<char>(carry + '0'));
    // Reverse back to obtain the final sum
    std::reverse(result.begin(), result.end());
    return result;
}

