// Function to swap `n` bits starting at positions `p1` and `p2` in the integer `x`
int swapBits(int x, int p1, int p2, int n) {
    // Extract the nth set of bits starting at positions p1 and p2
    int set1 = (x >> p1) & ((1 << n) - 1);
    int set2 = (x >> p2) & ((1 << n) - 1);
    // XOR the extracted sets to find the differing bits
    int xorBits = set1 ^ set2;
    // Put the differing bits back to their positions
    xorBits = (xorBits << p1) | (xorBits << p2);
    // Toggle the differing bits in x to get the final result
    return x ^ xorBits;
}
