int countUnique(const std::vector<std::vector<int>>& mat, int n, int m) {
    std::vector<int> rowsum(n, 0);
    std::vector<int> colsum(m, 0);
    // First pass: count non-zero elements in each row and column
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            if (mat[i][j] != 0) {
                ++rowsum[i];
                ++colsum[j];
            }
        }
    }
    // Second pass: count elements that are the only non-zero
    // in their respective row and column
    int uniquecount = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            if (mat[i][j] != 0 && rowsum[i] == 1 && colsum[j] == 1) {
                ++uniquecount;
            }
        }
    }
    return uniquecount;
}

