int countTransformation(const std::string& a, const std::string& b) {
    int n = static_cast<int>(a.length());
    int m = static_cast<int>(b.length());
    if (m == 0) {            // Empty string “b” can always be formed once
        return 1;
    }
    // dp[i][j] – number of ways first (i + 1) chars of b can be formed  
    //            from the first (j + 1) chars of a
    std::vector<std::vector<int>> dp(m, std::vector<int>(n, 0));
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < n; ++j) {          // j must be >= i
            if (i == 0) {                      // first row (matching b[0])
                if (j == 0) {
                    dp[i][j] = (a[j] == b[i]) ? 1 : 0;
                } else if (a[j] == b[i]) {
                    dp[i][j] = dp[i][j - 1] + 1;
                } else {
                    dp[i][j] = dp[i][j - 1];
                }
            } else {                           // i > 0
                if (a[j] == b[i]) {
                    dp[i][j] = dp[i][j - 1] + dp[i - 1][j - 1];
                } else {
                    dp[i][j] = dp[i][j - 1];
                }
            }
        }
    }
    return dp[m - 1][n - 1];
}

