// Returns 1 if n is a multiple of 3, otherwise returns 0
int isMultipleOf3(int n) {
    int odd_count  = 0;
    int even_count = 0;
    if (n < 0) n = -n;         // Make n non-negative
    if (n == 0) return 1;      // 0 is a multiple of 3
    if (n == 1) return 0;      // 1 is not a multiple of 3
    // Count set bits at odd and even positions
    while (n != 0) {
        if ((n & 1) != 0) odd_count++;   // Bit at position 0 (LSB)
        if ((n & 2) != 0) even_count++;  // Bit at position 1
        n >>= 2;                         // Shift out two bits
    }
    // Recurse with the absolute difference of counts
    return isMultipleOf3(std::abs(odd_count - even_count));
}

